CREATE POLICY "Mensagens de chat visíveis apenas para os envolvidos" ON public.messages FOR SELECT USING (
  EXISTS (
    SELECT 1 FROM public.offers 
    WHERE id = offer_id AND (sender_id = auth.uid() OR receiver_id = auth.uid())
  )
);

CREATE POLICY "Envolvidos na oferta enviam novas mensagens" ON public.messages FOR INSERT WITH CHECK (
  auth.uid() = sender_id AND 
  EXISTS (
    SELECT 1 FROM public.offers 
    WHERE id = offer_id AND (sender_id = auth.uid() OR receiver_id = auth.uid())
  )
);
